algorithms.pseudocode:
function gcd(a, b):
  while b != 0:
    a, b = b, a % b
  return a

function gcd(a, b):
  t = min(a, b)
  while t > 0:
    if a % t == 0 and b % t == 0: return t
    t = t - 1

function gcd(a, b):
  factorsA = primeFactorization(a)
  factorsB = primeFactorization(b)
  common = intersection(factorsA, factorsB)
  return product(common)

function factorial(n):
  if n == 0 or n == 1: return 1
  return n * factorial(n - 1)

function sequentialSearch(arr, target):
  for i = 0 to arr.length - 1:
    if arr[i] == target: return i
  return -1

function maxElement(arr):
  maxVal = arr[0]
  for i = 1 to arr.length - 1:
    if arr[i] > maxVal: maxVal = arr[i]
  return maxVal

function uniqueElements(arr):
  seen = new Set()
  for item in arr:
    if seen.has(item): return false
    seen.add(item)
  return true

function selectionSort(arr):
  for i = 0 to arr.length - 1:
    minIdx = i
    for j = i + 1 to arr.length:
      if arr[j] < arr[minIdx]: minIdx = j
    swap(arr[i], arr[minIdx])
  return arr

function bubbleSort(arr):
  n = arr.length
  for i = 0 to n - 1:
    for j = 0 to n - i - 2:
      if arr[j] > arr[j + 1]:
        swap(arr[j], arr[j + 1])
  return arr

function mergeSort(arr):
  if arr.length <= 1: return arr
  mid = arr.length / 2
  left = mergeSort(arr.slice(0, mid))
  right = mergeSort(arr.slice(mid))
  return merge(left, right)

function quickSort(arr, low, high):
  if low < high:
    pivotIdx = partition(arr, low, high)
    quickSort(arr, low, pivotIdx - 1)
    quickSort(arr, pivotIdx + 1, high)
  return arr

function heapSort(arr):
  buildMaxHeap(arr)
  for i = arr.length - 1 down to 1:
    swap(arr[0], arr[i])
    heapify(arr, 0, i)
  return arr

function dfs(graph, start, visited = new Set()):
  visited.add(start)
  for neighbor in graph[start]:
    if !visited.has(neighbor):
      dfs(graph, neighbor, visited)
  return visited

function bfs(graph, start):
  visited = new Set([start])
  queue = [start]
  while queue.length > 0:
    node = queue.shift()
    for neighbor in graph[node]:
      if !visited.has(neighbor):
        visited.add(neighbor)
        queue.push(neighbor)
  return visited

function kruskalMST(edges, numVertices):
  mst = [], ds = new DisjointSet(numVertices)
  edges.sort((a, b) => a.weight - b.weight)
  for edge in edges:
    if ds.find(edge.u) != ds.find(edge.v):
      ds.union(edge.u, edge.v)
      mst.push(edge)
  return mst

function dijkstra(graph, start):
  dist = map(), pq = new PriorityQueue()
  for node in graph: dist[node] = Infinity
  dist[start] = 0, pq.push(start, 0)
  while !pq.isEmpty():
    curr = pq.pop()
    for neighbor, weight in graph[curr]:
      newDist = dist[curr] + weight
      if newDist < dist[neighbor]:
        dist[neighbor] = newDist
        pq.push(neighbor, newDist)
  return dist

function minChange(coins, amount):
  dp = new Array(amount + 1).fill(Infinity)
  dp[0] = 0
  for i = 1 to amount:
    for coin in coins:
      if i - coin >= 0:
        dp[i] = min(dp[i], dp[i - coin] + 1)
  return dp[amount]

function coinCollecting(grid):
  rows = grid.length, cols = grid[0].length
  dp = new Array(rows).fill(0).map(() => new Array(cols).fill(0))
  dp[0][0] = grid[0][0]
  for i = 1 to rows - 1: dp[i][0] = dp[i-1][0] + grid[i][0]
  for j = 1 to cols - 1: dp[0][j] = dp[0][j-1] + grid[0][j]
  for i = 1 to rows - 1:
    for j = 1 to cols - 1:
      dp[i][j] = max(dp[i-1][j], dp[i][j-1]) + grid[i][j]
  return dp[rows-1][cols-1]

function buildHuffmanTree(freqMap):
  pq = new PriorityQueue()
  for char, freq in freqMap: pq.push(new Node(char, freq))
  while pq.size > 1:
    left = pq.pop(), right = pq.pop()
    parent = new Node(null, left.freq + right.freq, left, right)
    pq.push(parent)
  return pq.pop()

function backtrack(state):
  if isGoal(state): return state
  for option in getOptions(state):
    if isValid(option):
      apply(option)
      res = backtrack(state)
      if res: return res
      undo(option)
  return null

function branchAndBound(root):
  best = Infinity, pq = new PriorityQueue()
  pq.push(root)
  while !pq.isEmpty():
    node = pq.pop()
    if node.bound < best:
      if node.isLeaf: best = min(best, node.cost)
      else pq.pushAll(node.children())
  return best
